import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, NavLink } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { Zap, Award } from 'lucide-react';
import 'react-toastify/dist/ReactToastify.css';

import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './pages/Login';
import Register from './pages/Register';
import AdminDashboard from './pages/Admin/Dashboard';
import StudentDashboard from './pages/Student/Dashboard';
import RecruiterDashboard from './pages/Recruiter/Dashboard';
import InterviewRoom from './pages/Interview/InterviewRoom';
import InterviewAnalysis from './pages/Interview/InterviewAnalysis';
import './App.css';
import AIChat from './pages/Student/AIChat';
import PremiumResumeParser from "./pages/Student/PremiumResumeParser";
import MentorshipHub from './pages/Student/MentorshipHub'; // ✅ NEW IMPORT
import BecameMentor from './pages/Student/BecameMentor';
import DriveCalendar from './pages/Student/DriveCalendar';
import StudyGroups from './pages/Student/StudyGroups';
import LandingPage from './pages/LandingPage';
import TrackApplications from './pages/Student/TrackApplications';

// Protected Route Component
const ProtectedRoute = ({ children, allowedRoles }) => {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner">
          <div className="spinner"></div>
          <p>Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  if (allowedRoles && !allowedRoles.includes(user.role)) {
    return <Navigate to="/unauthorized" replace />;
  }

  return children;
};

// Public Route (redirect if logged in)
const PublicRoute = ({ children }) => {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner">
          <div className="spinner"></div>
          <p>Loading...</p>
        </div>
      </div>
    );
  }

  if (user) {
    // Redirect based on role
    if (user.role === 'admin') return <Navigate to="/admin" replace />;
    if (user.role === 'student') return <Navigate to="/student" replace />;
    if (user.role === 'recruiter') return <Navigate to="/recruiter" replace />;
  }

  return children;
};

// Unauthorized Page
const UnauthorizedPage = () => {
  const { user } = useAuth();
  
  return (
    <div className="unauthorized-container">
      <div className="unauthorized-card">
        <div className="unauthorized-icon">🚫</div>
        <h1>Access Denied</h1>
        <p>You don't have permission to access this page.</p>
        {user && (
          <div className="user-info">
            <p>Current Role: <strong>{user.role}</strong></p>
            <button 
              onClick={() => window.location.href = `/${user.role}`}
              className="btn-primary"
            >
              Go to Dashboard
            </button>
          </div>
        )}
        {!user && (
          <button 
            onClick={() => window.location.href = '/login'}
            className="btn-primary"
          >
            Login
          </button>
        )}
      </div>
    </div>
  );
};

// Not Found Page
const NotFoundPage = () => {
  const { user } = useAuth();
  
  return (
    <div className="not-found-container">
      <div className="not-found-card">
        <div className="not-found-icon">404</div>
        <h1>Page Not Found</h1>
        <p>The page you're looking for doesn't exist.</p>
        {user ? (
          <button 
            onClick={() => window.location.href = `/${user.role}`}
            className="btn-primary"
          >
            Go to Dashboard
          </button>
        ) : (
          <button 
            onClick={() => window.location.href = '/login'}
            className="btn-primary"
          >
            Go to Login
          </button>
        )}
      </div>
    </div>
  );
};

function App() {
  return (
    <AuthProvider>
      <Router>
        <div className="App">
          <Routes>
            {/* Landing Page - root route */}
            <Route path="/" element={<LandingPage />} />

            {/* Auth Routes */}
            <Route 
              path="/login" 
              element={
                <PublicRoute>
                  <Login />
                </PublicRoute>
              } 
            />
            
            <Route 
              path="/register" 
              element={
                <PublicRoute>
                  <Register />
                </PublicRoute>
              } 
            />
            
            {/* Interview Routes - Accessible by both students and recruiters */}
            <Route 
              path="/interview/room/:roomId" 
              element={
                <ProtectedRoute allowedRoles={['student', 'recruiter']}>
                  <InterviewRoom />
                </ProtectedRoute>
              } 
            />
            
            {/* Interview Analysis - Multiple paths for flexibility */}
            <Route 
              path="/interview/:interviewId/analysis" 
              element={
                <ProtectedRoute allowedRoles={['student', 'recruiter', 'admin']}>
                  <InterviewAnalysis />
                </ProtectedRoute>
              } 
            />
            
            <Route 
              path="/recruiter/interviews/:interviewId/analysis" 
              element={
                <ProtectedRoute allowedRoles={['recruiter', 'admin']}>
                  <InterviewAnalysis />
                </ProtectedRoute>
              } 
            />
            
            <Route 
              path="/student/interviews/:interviewId/analysis" 
              element={
                <ProtectedRoute allowedRoles={['student', 'admin']}>
                  <InterviewAnalysis />
                </ProtectedRoute>
              } 
            />

            {/* AI Chat Route */}
            <Route 
              path="/student/ai-chat" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <AIChat />
                </ProtectedRoute>
              } 
            />

            {/* Premium Resume Parser Route */}
            <Route 
              path="/student/premium-resume-parser" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <PremiumResumeParser />
                </ProtectedRoute>
              } 
            />

            {/* ✅ MENTORSHIP HUB ROUTES (NEW) */}
            <Route 
              path="/student/mentorship" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <MentorshipHub />
                </ProtectedRoute>
              } 
            />
            
            <Route 
              path="/student/become-mentor" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <BecameMentor />
                </ProtectedRoute>
              } 
            />

            {/* Drive Calendar Route */}
            <Route 
              path="/student/calendar" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <DriveCalendar />
                </ProtectedRoute>
              } 
            />

            {/* Study Groups Route */}
            <Route 
              path="/student/study-groups" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <StudyGroups />
                </ProtectedRoute>
              } 
            />

            {/* Track Applications Route */}
            <Route 
              path="/student/track-applications" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <TrackApplications />
                </ProtectedRoute>
              } 
            />
            
            {/* Role-based Dashboards */}
            <Route 
              path="/admin/*" 
              element={
                <ProtectedRoute allowedRoles={['admin']}>
                  <AdminDashboard />
                </ProtectedRoute>
              } 
            />
            
            <Route 
              path="/student/*" 
              element={
                <ProtectedRoute allowedRoles={['student']}>
                  <StudentDashboard />
                </ProtectedRoute>
              } 
            />
            
            <Route 
              path="/recruiter/*" 
              element={
                <ProtectedRoute allowedRoles={['recruiter']}>
                  <RecruiterDashboard />
                </ProtectedRoute>
              } 
            />
            
            {/* Special Pages */}
            <Route path="/unauthorized" element={<UnauthorizedPage />} />
            <Route path="*" element={<NotFoundPage />} />
          </Routes>
          
          {/* Toast Notifications */}
          <ToastContainer 
            position="top-right" 
            autoClose={3000}
            hideProgressBar={false}
            newestOnTop={true}
            closeOnClick
            rtl={false}
            pauseOnFocusLoss
            draggable
            pauseOnHover
            theme="light"
          />
        </div>
      </Router>
    </AuthProvider>
  );
}

export default App;

// Navigation Components for Student Sidebar/Menu

export const PremiumResumeParserNav = () => {
  return (
    <NavLink 
      to="/student/premium-resume-parser"
      className={({ isActive }) => isActive ? 'nav-item active' : 'nav-item'}
    >
      <Zap size={20} />
      <span>Premium Resume Parser</span>
    </NavLink>
  );
};

// ✅ NEW NAVIGATION COMPONENT FOR MENTORSHIP HUB
export const MentorshipHubNav = () => {
  return (
    <NavLink 
      to="/student/mentorship"
      className={({ isActive }) => isActive ? 'nav-item active' : 'nav-item'}
    >
      <Award size={20} />
      <span>Mentorship Hub</span>
    </NavLink>
  );
};

// ✅ NEW NAVIGATION COMPONENT FOR BECOME MENTOR
export const BecomeMentorNav = () => {
  return (
    <NavLink 
      to="/student/become-mentor"
      className={({ isActive }) => isActive ? 'nav-item active' : 'nav-item'}
    >
      <Award size={20} />
      <span>Become a Mentor</span>
    </NavLink>
  );
};
